PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT (YEAR(?birthDate) AS ?birthYear) WHERE {
  ?season wdt:P179 wd:Q1768525.
  ?season wdt:P1545 "38".

  ?episode wdt:P248 ?season;
    wdt:P31 wd:Q190409;
    wdt:P725 wd:Q314504;
    wdt:P123 ?host.

  ?host wdt:P569 ?birthDate.
}
